243|fn count_language_extensions(root: &Path, max_depth: usize) -> Vec<(SourceLanguage, u32)> {
244|    let mut counts: HashMap<SourceLanguage, u32> = HashMap::new();
245|    walk_files(root, max_depth, &mut |path| {
246|        if let Some(ext) = path.extension().and_then(|value| value.to_str()) {
247|            if let Some(language) = language_from_extension(ext) {
248|                *counts.entry(language).or_insert(0) += 1;
249|            }
250|        }
251|    });
252|
253|    let mut ranked: Vec<_> = counts.into_iter().collect();
254|    ranked.sort_by(|left, right| {
255|        right
256|            .1
257|            .cmp(&left.1)
258|            .then_with(|| left.0.as_str().cmp(right.0.as_str()))
259|    });
260|    ranked
261|}
