263|fn walk_files(root: &Path, max_depth: usize, visit: &mut dyn FnMut(&Path)) {
264|    fn walk(current: &Path, depth: usize, max_depth: usize, visit: &mut dyn FnMut(&Path)) {
265|        if depth > max_depth {
266|            return;
267|        }
268|
269|        let entries = match fs::read_dir(current) {
270|            Ok(entries) => entries,
271|            Err(_) => return,
272|        };
273|
274|        for entry in entries.flatten() {
275|            let path = entry.path();
276|            if should_skip(&path) {
277|                continue;
278|            }
279|
280|            if path.is_dir() {
281|                walk(&path, depth + 1, max_depth, visit);
282|            } else if path.is_file() {
283|                visit(&path);
284|            }
285|        }
286|    }
287|
288|    walk(root, 0, max_depth, visit);
289|}
