201|    fn run_build_targets(
202|        &self,
203|        targets: &[(PathBuf, String)],
204|        context: &mut AgentContext,
205|    ) -> Result<bool, String> {
206|        let mut combined_errors = Vec::new();
207|        let mut all_ok = true;
208|
209|        for (dir, command) in targets {
210|            match self.build_runner.run_build_command(dir, command) {
211|                Ok(output) => {
212|                    let (body, truncated) = truncate_build_log(
213|                        &output,
214|                        Self::BUILD_LOG_MAX_LINES,
215|                        Self::BUILD_LOG_MAX_BYTES,
216|                    );
217|                    let log = if truncated {
218|                        format!("(log truncated)\n{body}")
219|                    } else {
220|                        body
221|                    };
222|                    let step = format!("Build OK in {} (`{command}`):\n{log}\n", dir.display());
223|                    context.accumulated_data.push_str(&step);
224|                }
225|                Err(output) => {
226|                    all_ok = false;
227|                    let (body, truncated) = truncate_build_log(
228|                        &output,
229|                        Self::BUILD_LOG_MAX_LINES,
230|                        Self::BUILD_LOG_MAX_BYTES,
231|                    );
232|                    let log = if truncated {
233|                        format!("(log truncated — showing tail)\n{body}")
234|                    } else {
235|                        body
236|                    };
237|                    combined_errors.push(format!(
238|                        "Build FAILED in {} (`{command}`):\n{log}\n",
239|                        dir.display()
240|                    ));
241|                }
242|            }
243|        }
244|
245|        if all_ok {
246|            context.is_finished = true;
247|            context.input_prompt = "All builds/tests completed successfully.".to_string();
248|        } else if !combined_errors.is_empty() {
249|            context
250|                .accumulated_data
251|                .push_str(&combined_errors.join("\n---\n"));
252|        }
253|
254|        Ok(all_ok)
255|    }
