271|                    ));
272|                }
273|                Err(output) => {
274|                    let (body, truncated) = truncate_build_log(
275|                        &output,
276|                        Self::BUILD_LOG_MAX_LINES,
277|                        Self::BUILD_LOG_MAX_BYTES,
278|                    );
279|                    let log = if truncated {
