281|                    } else {
282|                        body
283|                    };
284|                    check_failures.push(format!(
285|                        "TDD RED check FAILED in {} (`{check_cmd}`):\n{log}\n",
286|                        dir.display()
287|                    ));
288|                }
289|            }
290|        }
