510|fn scope_test_command_for_paths(test_cmd: &str, test_paths: &[PathBuf]) -> String {
511|    if !test_cmd.starts_with("cargo test") || test_paths.len() != 1 {
512|        return test_cmd.to_string();
513|    }
514|
515|    let path = &test_paths[0];
516|    let in_tests_dir = path
517|        .components()
518|        .any(|component| component.as_os_str() == "tests");
519|    let Some(stem) = path.file_stem().and_then(|name| name.to_str()) else {
520|        return test_cmd.to_string();
521|    };
522|
523|    if in_tests_dir && path.extension().is_some_and(|ext| ext == "rs") {
524|        insert_cargo_test_filter(test_cmd, stem)
525|    } else {
526|        test_cmd.to_string()
527|    }
