530|fn insert_cargo_test_filter(test_cmd: &str, stem: &str) -> String {
531|    let (head, tail) = match test_cmd.split_once(" -- ") {
532|        Some(parts) => parts,
533|        None => (test_cmd, ""),
534|    };
535|
536|    if head.contains("--test ") {
537|        return test_cmd.to_string();
538|    }
539|
540|    let scoped_head = format!("{head} --test {stem}");
541|    if tail.is_empty() {
542|        scoped_head
543|    } else {
544|        format!("{scoped_head} -- {tail}")
545|    }
