548|fn is_setup_test_failure(output: &str) -> bool {
549|    let lower = output.to_lowercase();
550|    lower.contains("no such file or directory")
551|        || lower.contains("failed to canonicalize")
552|        || lower.contains("e0433:")
553|        || lower.contains("e0061:")
554|        || lower.contains("e0599:")
555|        || lower.contains("unresolved import")
556|        || lower.contains("tempfile::")
