559|fn is_assertion_test_failure(output: &str, test_paths: &[PathBuf], command_scoped: bool) -> bool {
560|    if is_setup_test_failure(output) {
561|        return false;
562|    }
563|
564|    let lower = output.to_lowercase();
565|    let has_assertion_signal = lower.contains("assertion `")
566|        || lower.contains("assert_eq!")
567|        || lower.contains("assertion failed")
568|        || (lower.contains("panicked at") && lower.contains("assert"));
569|
570|    if !has_assertion_signal {
571|        return false;
572|    }
573|
574|    if command_scoped || test_paths.is_empty() {
575|        return true;
576|    }
577|
578|    test_paths.iter().any(|path| {
579|        path.file_stem()
580|            .and_then(|stem| stem.to_str())
581|            .is_some_and(|stem| lower.contains(&stem.to_lowercase()))
582|    })
583|}
