589|fn paths_equivalent(left: &Path, right: &Path) -> bool {
590|    if left == right {
591|        return true;
592|    }
593|    match (std::fs::canonicalize(left), std::fs::canonicalize(right)) {
594|        (Ok(left), Ok(right)) => left == right,
595|        _ => false,
596|    }
