599|fn assert_edit_allowed(resolved: &Path, editable_paths: &[PathBuf]) -> Result<(), String> {
600|    if is_protected_test_infra(resolved) {
601|        return Err(format!(
602|            "{} is shared test infrastructure — edit the generated test file instead",
603|            resolved.display()
604|        ));
605|    }
606|    if editable_paths.is_empty() {
607|        return Ok(());
608|    }
609|    if editable_paths
610|        .iter()
611|        .any(|allowed| paths_equivalent(resolved, allowed))
612|    {
613|        return Ok(());
614|    }
615|    Err(format!(
616|        "{} is outside builder triage scope (editable: {})",
617|        resolved.display(),
618|        editable_paths
619|            .iter()
620|            .map(|path| path.display().to_string())
621|            .collect::<Vec<_>>()
622|            .join(", ")
623|    ))
