626|fn resolve_edit_path(path: &Path, module_roots: &[PathBuf]) -> Result<PathBuf, String> {
627|    if path.is_absolute() {
628|        for root in module_roots {
629|            if root.as_os_str().is_empty() {
630|                continue;
631|            }
632|            if path.starts_with(root) {
633|                return Ok(path.to_path_buf());
634|            }
635|        }
636|        return Err(format!(
637|            "edit path must be relative to a triage module root: {}",
638|            path.display()
639|        ));
640|    }
641|
642|    if path
643|        .components()
644|        .any(|component| matches!(component, Component::ParentDir))
645|    {
646|        return Err(format!("edit path must not contain ..: {}", path.display()));
647|    }
648|
649|    for root in module_roots {
650|        if root.as_os_str().is_empty() {
651|            continue;
652|        }
653|        let candidate = root.join(path);
654|        if candidate.starts_with(root) {
655|            return Ok(candidate);
656|        }
657|    }
658|
659|    Err(format!(
660|        "edit path must be inside a triage module root: {}",
661|        path.display()
662|    ))
