211|pub fn find_refactor_targets(type_name: &str) -> Result<Vec<RefactorTarget>, String> {
212|    let pattern = format!(r"\b{}\b", regex_escape(type_name));
213|    let candidate_files = run_ripgrep_files(&pattern, &mcp_workspace_root())?;
214|
215|    let mut by_file: BTreeMap<PathBuf, RefactorTarget> = BTreeMap::new();
216|
217|    for file in candidate_files {
218|        let path = resolve_workspace_path(&file);
219|        if !is_production_src_file(&path)
220|            || is_skipped_refactor_file(&path)
221|            || !path.exists()
222|            || is_type_definition_file(&path, type_name)
223|        {
224|            continue;
225|        }
226|
227|        let mut ranges =
228|            AstUsageFinder::find_construction_sites_in_file(&path, type_name).unwrap_or_default();
229|        let call_ranges =
230|            AstUsageFinder::find_call_expression_ranges_in_file(&path, type_name).unwrap_or_default();
231|        for range in call_ranges {
232|            if !ranges.iter().any(|existing| existing.start == range.start && existing.end == range.end) {
233|                ranges.push(range);
234|            }
235|        }
236|
237|        let call_lines = AstUsageFinder::find_calls_in_file(&path, type_name).unwrap_or_default();
238|
239|        for line in call_lines {
240|            if !ranges.iter().any(|range| line >= range.start && line <= range.end) {
241|                ranges.push(LineRange {
242|                    start: line,
243|                    end: line,
244|                });
245|            }
246|        }
247|
248|        if ranges.is_empty()
249|            && detect_file_language(&path)
250|                .map(|report| report.language == SourceLanguage::Unknown)
251|                .unwrap_or(true)
252|        {
253|            if let Ok(content) = std::fs::read_to_string(&path) {
254|                let lines: Vec<&str> = content.lines().collect();
255|                for (idx, line) in lines.iter().enumerate() {
256|                    if line_has_identifier(line, type_name) {
257|                        let range = if line.contains('{') {
258|                            expand_brace_range(&lines, idx)
259|                        } else {
260|                            LineRange {
261|                                start: idx + 1,
262|                                end: idx + 1,
263|                            }
264|                        };
265|                        ranges.push(range);
266|                    }
267|                }
268|            }
269|        }
270|
271|        if ranges.is_empty() {
272|            continue;
273|        }
274|
275|        drop_subset_ranges(&mut ranges);
276|
277|        let entry = by_file.entry(path.clone()).or_insert_with(|| RefactorTarget {
278|            file_path: path,
279|            lines: Vec::new(),
280|            ranges: Vec::new(),
281|        });
282|
283|        for range in ranges {
284|            let target_range = TargetLineRange {
285|                start: range.start,
286|                end: range.end,
287|            };
288|            if !entry.ranges.contains(&target_range) {
289|                entry.ranges.push(target_range);
290|            }
291|        }
292|    }
293|
294|    Ok(by_file.into_values().collect())
295|}
