345|fn is_production_src_file(path: &Path) -> bool {
346|    let normalized = path.to_string_lossy().replace('\\', "/");
347|    if normalized.contains("/tests/") || normalized.contains("/fixtures/") {
348|        return false;
349|    }
350|    (normalized.contains("/src/") && normalized.ends_with(".rs"))
351|        || (normalized.contains("/frontend/src/")
352|            && (normalized.ends_with(".ts") || normalized.ends_with(".tsx"))
353|            && !normalized.ends_with(".d.ts"))
354|        || (normalized.contains("/scripts/sort_demo/") && normalized.ends_with(".py"))
355|        || (normalized.contains("/scripts/sort_demo_java/") && normalized.ends_with(".java"))
356|        || (normalized.contains("/scripts/sort_demo_kotlin/") && normalized.ends_with(".kt"))
357|        || (normalized.contains("/scripts/sort_demo_cpp/") && normalized.ends_with(".cpp"))
358|        || (normalized.contains("/scripts/sort_demo_c/") && normalized.ends_with(".c"))
359|        || (normalized.contains("/scripts/sort_demo_zig/") && normalized.ends_with(".zig"))
360|}
