371|fn is_type_definition_file(path: &Path, type_name: &str) -> bool {
372|    let Ok(content) = std::fs::read_to_string(path) else {
373|        return false;
374|    };
375|    content.contains(&format!("struct {type_name}"))
376|        || content.contains(&format!("enum {type_name}"))
377|        || content.contains(&format!("class {type_name}"))
378|        || content.contains(&format!("interface {type_name}"))
379|        || content.contains(&format!("export interface {type_name}"))
380|        || content.contains(&format!("function {type_name}"))
381|        || content.contains(&format!("export function {type_name}"))
382|        || content.contains(&format!("def {type_name}"))
383|        || content.contains(&format!("void {type_name}("))
384|        || content.contains(&format!("static void {type_name}("))
385|        || content.contains(&format!("fun {type_name}("))
386|        || content.contains(&format!("pub fn {type_name}("))
