389|fn regex_escape(input: &str) -> String {
390|    input
391|        .chars()
392|        .map(|ch| {
393|            if ch.is_ascii_alphanumeric() || ch == '_' {
394|                ch.to_string()
395|            } else {
396|                format!("\\{ch}")
397|            }
398|        })
399|        .collect()
400|}
