69|fn infer_source_module(file_path: &Path, instruction: &str) -> Option<String> {
70|    let file = file_path.to_string_lossy();
71|    if file.contains("orchestrator") {
72|        return Some("agent::orchestrator".to_string());
73|    }
74|    if file.contains("config_server") {
75|        return Some("config_server".to_string());
76|    }
77|    if file.contains("handlers") {
78|        return Some("mcp::handlers".to_string());
79|    }
80|    if file.contains("jobs.rs") {
81|        return Some("jobs".to_string());
82|    }
83|
84|    for line in instruction.lines() {
85|        if let Some((_, module)) = line.split_once('→').or_else(|| line.split_once("->")) {
86|            let module = module.trim().trim_matches('"');
87|            if !module.is_empty() {
88|                return Some(module.to_string());
89|            }
90|        }
91|    }
92|
93|    file_path
94|        .file_stem()
95|        .and_then(|s| s.to_str())
96|        .map(str::to_string)
